# Parse puzzles
lines = [l.strip() for l in text.splitlines()]

def extract_block(header):
    try:
        i = lines.index(header)
    except ValueError:
        return None
    block = []
    j = i+1
    while j < len(lines) and len(block) < 9:
        if lines[j] != "":
            block.append(lines[j])
        j += 1
    return block if len(block)==9 else None

orig = extract_block("ORIGINAL_PUZZLE:")
sol = extract_block("SOLUTION_PUZZLE:")
unit_index = None
# find UNIT_INDEX line
for l in lines:
    if l.startswith("UNIT_INDEX:"):
        try:
            unit_index = int(l.split(":",1)[1].strip())
        except:
            unit_index = None

if orig is None or sol is None or unit_index is None:
    issue = "failed to parse context"
    done({"index": unit_index if unit_index is not None else 0, "ok": False, "issue": issue})

# Collect column values
col_orig = [row[unit_index] for row in orig]
col_sol = [row[unit_index] for row in sol]

# Check given cells match
mismatch = []
for r,(o,s) in enumerate(zip(col_orig, col_sol)):
    if o != '0' and o != '.' and o != '':
        if o != s:
            mismatch.append((r,o,s))

if mismatch:
    issue = f"mismatch at rows: " + ", ".join(f"{r} orig={o} sol={s}" for r,o,s in mismatch)
    done({"index": unit_index, "ok": False, "issue": issue})

# Check solution column is a permutation of 1..9
digits = col_sol
if sorted(digits) != list("123456789"):
    # find duplicates or missing
    issue = "solution column does not contain digits 1-9 exactly once"
    done({"index": unit_index, "ok": False, "issue": issue})

# All good
done({"index": unit_index, "ok": True, "issue": ""})
